# .github/workflows/sla-monitor.yml
name: Review SLA Monitor

on:
  schedule:
    # Run every hour during business hours (Mon-Fri 09:00-18:00 UTC)
    - cron: '0 9-18 * * 1-5'

jobs:
  check-sla:
    runs-on: ubuntu-latest
    steps:
      - name: Check overdue PRs
        uses: actions/github-script@v7
        with:
          script: |
            const { data: prs } = await github.rest.pulls.list({
              owner: context.repo.owner,
              repo: context.repo.repo,
              state: 'open',
              labels: 'prompt-change',
            });

            const SLA_HOURS = { standard: 72, major: 72, 'security-expedited': 2, 'patch-only': 120 };
            const now = Date.now();
            const overdue = [];

            for (const pr of prs) {
              const tier = pr.labels.find(l => l.name in SLA_HOURS)?.name ?? 'standard';
              const slaMs = SLA_HOURS[tier] * 3600 * 1000;
              const ageMs = now - new Date(pr.created_at).getTime();
              if (ageMs > slaMs && pr.requested_reviewers.length > 0) {
                overdue.push({ number: pr.number, title: pr.title, tier, ageHours: Math.floor(ageMs / 3600000) });
              }
            }

            if (overdue.length > 0) {
              // Post to Slack via repository secret SLACK_WEBHOOK_URL
              const msg = overdue.map(p =>
                `PR #${p.number} (${p.tier}) overdue by ${p.ageHours - SLA_HOURS[p.tier]}h: ${p.title}`
              ).join('\n');
              await fetch(process.env.SLACK_WEBHOOK_URL, {
                method: 'POST',
                body: JSON.stringify({ text: ':warning: Overdue prompt review PRs:\n' + msg }),
              });
            }
        env:
          SLACK_WEBHOOK_URL: ${{ secrets.SLACK_WEBHOOK_URL }}

# scripts/check-pr-label.py — called from CI on PR open
import os, sys
import requests

VALID_LABELS = {"standard", "major", "security-expedited", "patch-only"}

def check_labels(repo: str, pr_number: int, token: str) -> None:
    url = f"https://api.github.com/repos/{repo}/issues/{pr_number}/labels"
    resp = requests.get(url, headers={"Authorization": f"Bearer {token}"})
    resp.raise_for_status()
    labels = {l["name"] for l in resp.json()}
    sla_labels = labels & VALID_LABELS
    if not sla_labels:
        print(
            f"ERROR: PR #{pr_number} touches the prompts/ directory but has no SLA tier label. "
            f"Add one of: {', '.join(sorted(VALID_LABELS))}"
        )
        sys.exit(1)
    if len(sla_labels) > 1:
        print(f"ERROR: PR #{pr_number} has multiple SLA labels: {sla_labels}. Use exactly one.")
        sys.exit(1)
    print(f"SLA label valid: {next(iter(sla_labels))}")

if __name__ == "__main__":
    check_labels(
        repo=os.environ["GITHUB_REPOSITORY"],
        pr_number=int(os.environ["PR_NUMBER"]),
        token=os.environ["GITHUB_TOKEN"],
    )

# .github/workflows/notify-review.yml
name: Notify Reviewers on Prompt PR

on:
  pull_request:
    types: [opened, ready_for_review]
    paths: ['prompts/**']

jobs:
  notify:
    runs-on: ubuntu-latest
    if: github.event.pull_request.draft == false
    steps:
      - name: Post to Slack
        uses: slackapi/slack-github-action@v1.26.0
        with:
          payload: |
            {
              "text": ":pencil: New prompt change PR ready for review",
              "blocks": [
                {
                  "type": "section",
                  "text": {
                    "type": "mrkdwn",
                    "text": "*<${{ github.event.pull_request.html_url }}|${{ github.event.pull_request.title }}>*\nAuthor: ${{ github.event.pull_request.user.login }} | Label: ${{ join(github.event.pull_request.labels.*.name, ', ') }}"
                  }
                },
                {
                  "type": "actions",
                  "elements": [
                    {
                      "type": "button",
                      "text": { "type": "plain_text", "text": "Open PR" },
                      "url": "${{ github.event.pull_request.html_url }}"
                    }
                  ]
                }
              ]
            }
        env:
          SLACK_WEBHOOK_URL: ${{ secrets.SLACK_PROMPT_REVIEWS_WEBHOOK }}
          SLACK_WEBHOOK_TYPE: INCOMING_WEBHOOK
